<#
.SYNOPSIS
  Writes one immutable, sanitized blindspot observation under run-traces.
#>
param([Parameter(Mandatory=$true)][string]$ObservationPath,[switch]$PassThru)
$ErrorActionPreference='Stop';$root=(Resolve-Path(Join-Path $PSScriptRoot '..\..')).Path;$o=Get-Content -LiteralPath $ObservationPath -Raw -Encoding UTF8|ConvertFrom-Json;$issues=[System.Collections.Generic.List[string]]::new();foreach($f in @('observation_id','task_id','task_type','collaboration_id','participant_refs','model_versions','claim_pack_refs','disagreement_type','final_outcome_ref','attribution','verified_by','classification','created_at')){if($null-eq$o.$f-or[string]::IsNullOrWhiteSpace([string]$o.$f)){[void]$issues.Add($f+'_required')}};if([string]$o.classification-notin@('public','internal_sanitized')){[void]$issues.Add('classification_denied')};if([string]$o.verified_by-match'^(model|agent):'){[void]$issues.Add('self_verification_denied')};if([string]$o.attribution-notin@('model','agent_scaffold','tool','data','policy','human_decision','coincidence','unresolved')){[void]$issues.Add('invalid_attribution')}
$dir=Join-Path $root '.qianlima\run-traces\blindspots';$out=Join-Path $dir ($o.observation_id+'.json');if(Test-Path -LiteralPath $out){[void]$issues.Add('observation_immutable')};if($issues.Count){$r=[ordered]@{status='rejected';issues=@($issues);production_authority='none'};if($PassThru){$r|ConvertTo-Json -Depth 6}else{[pscustomobject]$r|Format-List};exit 1};New-Item -ItemType Directory -Path $dir -Force|Out-Null;$record=[ordered]@{};foreach($p in $o.PSObject.Properties){$record[$p.Name]=$p.Value};$record.production_authority='none';$record.permission_change='none';[IO.File]::WriteAllText($out,($record|ConvertTo-Json -Depth 10),[Text.UTF8Encoding]::new($false));$r=[ordered]@{status='recorded';observation_id=$o.observation_id;reference='blindspots/'+(Split-Path -Leaf $out);production_authority='none';permissions_granted=$false};if($PassThru){$r|ConvertTo-Json -Depth 6}else{[pscustomobject]$r|Format-List}
